class EventEmitter:
    def __init__(self):
        self._listeners = {}

    def on(self, event, listener):
        if event not in self._listeners:
            self._listeners[event] = []
        self._listeners[event].append(listener)

    def off(self, event, listener):
        if event in self._listeners and listener in self._listeners[event]:
            self._listeners[event].remove(listener)

    def emit(self, event, *args):
        if event in self._listeners:
            # Iterate over a copy to allow listeners to modify the list during execution
            for listener in list(self._listeners[event]):
                try:
                    listener(*args)
                except Exception as e:
                    print(f"Error in listener for {event}: {e}")

# Example usage (optional, but helpful for development):
if __name__ == '__main__':
    emitter = EventEmitter()
    def handler1(data):
        print("Handler 1 called with:", data)
    def handler2(data):
        print("Handler 2 called with:", data)

    emitter.on("data", handler1)
    emitter.on("data", handler2)
    emitter.emit("data", "Test payload")

    emitter.off("data", handler1)
    emitter.emit("data", "Second test payload")

